function cardPressed(){this.classList.add("card-hover")}function cardReleased(){this.classList.remove("card-hover")}function hamburgerMenuPressed(){this.checked?(this.setAttribute("aria-expanded","true"),document.body.style.paddingRight=window.innerWidth-document.documentElement.clientWidth+"px",document.body.classList.add("no-scroll")):(this.setAttribute("aria-expanded","false"),document.body.classList.remove("no-scroll"),document.body.style.paddingRight=0+"px")}document.addEventListener("DOMContentLoaded",function(){document.querySelectorAll(".blog-card").forEach(function(e){e.addEventListener("touchstart",function(){cardPressed.call(e)},{passive:!0}),e.addEventListener("touchend",function(){cardReleased.call(e)},{passive:!0}),e.addEventListener("touchmove",function(){cardReleased.call(e)},{passive:!0}),e.addEventListener("touchcancel",function(){cardReleased.call(e)},{passive:!0})});const e=document.querySelector(".hamburger-menu-button");if(!e)return;document.querySelectorAll(".hamburger-menu-overlay-link").forEach(function(t){t.addEventListener("click",function(){e.checked=!1,hamburgerMenuPressed.call(e)})}),document.addEventListener("keydown",function(t){t.key==="Escape"&&e.checked&&(e.checked=!1,hamburgerMenuPressed.call(e))})})